+/** A captured expression is used to stringify the result before evaluation.
+ * When an expression evaluates to `false`, the string is reported to the user. */
+template <typename T>
+struct CapturedExpression {
+    const T& lhs;
+
+    /** No right-hand-side exists to evaluate. */
+    operator Result() const
+    {
+        return static_cast<bool>(lhs) ? Result::ok() : Result::failed(stringify(lhs));
+    }
+
+    template <typename U>
+    auto operator&&(const U&) = delete;
+
+    template <typename U>
+    auto operator||(const U&) = delete;
+
+#define DECOMPOSE_OP(op)                                                                                       \
+    template <typename U>                                                                                      \
+    Result operator op(const U& rhs) const                                                                     \
+    {                                                                                                          \
+        if constexpr (std::is_integral_v<T> && std::is_integral_v<U>) {                                        \
+            static_assert(                                                                                     \
+                std::is_signed_v<decltype(std::declval<T>() + 0)> ==                                           \
+                    std::is_signed_v<decltype(std::declval<U>() + 0)>,                                         \
+                "Mixed signed/unsigned comparison in CHECK/REQUIRE; cast one side explicitly");                \
+        }                                                                                                      \
+        bool btc_test_result = static_cast<bool>(lhs op rhs);                                                  \
+        return btc_test_result ? Result::ok() : Result::failed(stringify(lhs) + " " #op " " + stringify(rhs)); \
+    }
+
+    DECOMPOSE_OP(==)
+    DECOMPOSE_OP(!=)
+    DECOMPOSE_OP(<)
+    DECOMPOSE_OP(<=)
+    DECOMPOSE_OP(>)
+    DECOMPOSE_OP(>=)
+#undef DECOMPOSE_OP
+};
